-- Opencode theme (full slot coverage, dark + light paired).
-- Shape per https://opencode.ai/theme.json; uses `defs` palette refs.
local function oc_pair(dark, light)
  return '{ "dark": "' .. dark .. '", "light": "' .. light .. '" }'
end
