local changed = {}
for path, content in pairs(generated) do
  if write_if_changed(path, content) then
    table.insert(changed, path)
  end
end

table.sort(changed)
if #changed == 0 then
  print('ports generator: no changes')
else
  print('ports generator: updated ' .. table.concat(changed, ', '))
end
